import React, { useState, useEffect } from 'react';
import AddHabitForm from './components/AddHabitForm';
import HabitList from './components/HabitList';
import Stats from './components/Stats';

function App() {
  const [habits, setHabits] = useState([]);

  useEffect(() => {
    const storedHabits = localStorage.getItem('habits');
    if (storedHabits) {
      setHabits(JSON.parse(storedHabits));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('habits', JSON.stringify(habits));
  }, [habits]);

  const deleteHabit = (id) => {
    setHabits(habits.filter(h => h.id !== id));
  };

  const exportData = () => {
    const dataStr = JSON.stringify(habits, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);
    const exportFileDefaultName = 'habits.json';
    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();
  };

  const toggleCompletion = (id, date, intensity) => {
    setHabits(habits.map(habit => {
      if (habit.id === id) {
        const completions = { ...habit.completions };
        completions[date] = intensity;
        return { ...habit, completions };
      }
      return habit;
    }));
  };

  const totalScore = habits.reduce((total, habit) => {
    return total + Object.values(habit.completions).reduce((sum, val) => sum + (val || 0), 0);
  }, 0);

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-200 via-purple-200 to-pink-200 p-4">
      <h1 className="text-4xl font-bold text-center mb-8 text-purple-900">Habit Tracker</h1>
      <div className="text-center mb-4 text-lg font-semibold text-indigo-800">Total Score: {totalScore}</div>
      <Stats habits={habits} />
      <AddHabitForm onAdd={addHabit} />
      <HabitList habits={habits} onToggle={toggleCompletion} onDelete={deleteHabit} onEdit={editHabit} />
    </div>
  );
}

export default App;
